// -----------------------------------------------------------------------// UnityPilot Editor — M25 RShell：UDP 与协议在 Bridge 内实现（Python 仅转发 WS）// 协议对齐 RShell UdpHost：https://github.com/CharlesFeng207/RShell/blob/main/Runtime/UdpHost.cs// -----------------------------------------------------------------------using System;using System.Collections.Concurrent;using System.Collections.Generic;using System.Linq;using System.Net;using System.Net.Sockets;using System.Text;using System.Threading;using System.Threading.Tasks;using UnityEditor;using UnityEngine;namespace codingriver.unity.pilot{    /// <summary>与 RShell UdpHost 发送的 JSON 分片字段一致（Unity JsonUtility）</summary>    [Serializable]    public class RShellWireMessage    {        public int MsgId;        public int FragIndex;        public int FragCount;        public string Content;        public string CheckMsg;    }    /// <summary>按 MsgId 重组 Content；单 MsgId 累计不超过 10MB</summary>    public sealed class RShellFragmentAssembler    {        private const int MaxTotalChars = 10 * 1024 * 1024;        private sealed class State        {            public int FragCount;            public string[] Parts;            public int TotalChars;        }        private readonly Dictionary<int, State> _byMsg = new();        public bool TryAdd(string jsonText, out string completed)        {            completed = null;            if (string.IsNullOrEmpty(jsonText) || jsonText[0] != '{')                return false;            RShellWireMessage m;            try            {                m = JsonUtility.FromJson<RShellWireMessage>(jsonText);            }            catch            {                return false;            }            if (m.FragCount <= 0)                m.FragCount = 1;            if (!_byMsg.TryGetValue(m.MsgId, out var st))            {                st = new State                {                    FragCount = m.FragCount,                    Parts = new string[m.FragCount],                };                _byMsg[m.MsgId] = st;            }            if (m.FragIndex < 0 || m.FragIndex >= st.Parts.Length)                return false;            var c = m.Content ?? "";            st.TotalChars += c.Length;            if (st.TotalChars > MaxTotalChars)            {                _byMsg.Remove(m.MsgId);                return false;            }            st.Parts[m.FragIndex] = c;            if (!st.Parts.Any(x => x == null))            {                completed = string.Concat(st.Parts);                _byMsg.Remove(m.MsgId);                return true;            }            return false;        }        public void ClearMsg(int msgId)        {            _byMsg.Remove(msgId);        }    }    public sealed class RShellSession    {        public string Id;        public UdpClient Client;        public string Host;        public int Port;        public string Status = "disconnected";        public string Error = "";        public long LastHeartbeatMs;        public readonly object UdpLock = new();        public System.Threading.Timer HeartbeatTimer;        public int MissCount;        public int TimeoutMs = 10000;        public int MaxRetries = 3;    }    [InitializeOnLoad]    public static class UnityPilotRShellLifecycle    {        static UnityPilotRShellLifecycle()        {            AssemblyReloadEvents.beforeAssemblyReload += DisposeAll;            EditorApplication.quitting += DisposeAll;        }        public static void DisposeAll() => UnityPilotRShellService.DisposeAllSessionsInternal();    }    public sealed class UnityPilotRShellService    {        private const int MaxConnections = 10;        private static readonly ConcurrentDictionary<string, RShellSession> Sessions = new();        private readonly UnityPilotBridge _bridge;        public UnityPilotRShellService(UnityPilotBridge bridge)        {            _bridge = bridge;            Logger.Log("[RShell] RShellService 初始化");        }        public void RegisterCommands()        {            _bridge.Router.Register("rshell.connect", HandleConnectAsync);            _bridge.Router.Register("rshell.disconnect", HandleDisconnectAsync);            _bridge.Router.Register("rshell.status", HandleStatusAsync);            _bridge.Router.Register("rshell.execute", HandleExecuteAsync);            _bridge.Router.Register("rshell.scene_list", HandleSceneListAsync);            _bridge.Router.Register("rshell.scene_info", HandleSceneInfoAsync);            _bridge.Router.Register("rshell.get_value", HandleGetValueAsync);            _bridge.Router.Register("rshell.set_value", HandleSetValueAsync);            _bridge.Router.Register("rshell.call_method", HandleCallMethodAsync);        }        public static void DisposeAllSessionsInternal()        {            foreach (var kv in Sessions.ToArray())            {                try                {                    DisposeSession(kv.Value);                }                catch                {                    // ignored                }                Sessions.TryRemove(kv.Key, out _);            }        }        private static void DisposeSession(RShellSession s)        {            if (s == null)                return;            s.HeartbeatTimer?.Dispose();            s.HeartbeatTimer = null;            lock (s.UdpLock)            {                try                {                    s.Client?.Close();                }                catch                {                    // ignored                }                s.Client = null;            }            s.Status = "disconnected";        }        private static bool TryParseIPv4(string host, out IPAddress addr)        {            addr = null;            if (string.IsNullOrWhiteSpace(host))                return false;            if (!IPAddress.TryParse(host.Trim(), out var a))                return false;            if (a.AddressFamily != AddressFamily.InterNetwork)                return false;            addr = a;            return true;        }        private static string EscapeCsString(string path)        {            if (path == null)                return "\"\"";            return "\"" + path.Replace("\\", "\\\\").Replace("\"", "\\\"") + "\"";        }        private async Task HandleConnectAsync(string id, string json, CancellationToken token)        {            var msg = JsonUtility.FromJson<RShellConnectMessage>(json);            var p = msg?.payload ?? new RShellConnectPayload();            var host = (p.host ?? "").Trim();            var port = p.port <= 0 ? 9999 : p.port;            var timeoutMs = p.timeoutMs <= 0 ? 10000 : Mathf.Clamp(p.timeoutMs, 1000, 60000);            var maxRetries = p.maxRetries < 0 ? 3 : Mathf.Clamp(p.maxRetries, 0, 20);            Logger.Log("RShell", $"开始连接 host={host} port={port} timeout={timeoutMs}ms retries={maxRetries} id={id}");            if (!TryParseIPv4(host, out _))            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", $"host \"{host}\" 不是合法的 IPv4 地址", token, "rshell.connect");                return;            }            if (port < 1024 || port > 65535)            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", $"port {port} 超出合法范围 [1024, 65535]", token, "rshell.connect");                return;            }            foreach (var kv in Sessions)            {                if (kv.Value.Status == "connected" &&                    string.Equals(kv.Value.Host, host, StringComparison.OrdinalIgnoreCase) &&                    kv.Value.Port == port)                {                    await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", $"同一 host:port 已存在 connected 连接 {kv.Key}", token, "rshell.connect");                    return;                }            }            if (Sessions.Count >= MaxConnections)            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", "并发连接数已达上限 10", token, "rshell.connect");                return;            }            try            {                var result = await Task.Run(                    () => DoConnect(host, port, timeoutMs, maxRetries, token),                    token).ConfigureAwait(true);                if (!result.ok)                {                    Logger.LogWarning("RShell", $"连接失败: host={host}:{port} error={result.error}");                    await _bridge.SendErrorAsync(id, "RSHELL_CONNECT_FAILED", result.error ?? "connect failed", token, "rshell.connect");                    return;                }                Logger.Log("RShell", $"连接成功: host={host}:{port} connectionId={result.connectionId}");                await _bridge.SendResultAsync(id, "rshell.connect", result, token);            }            catch (OperationCanceledException)            {                await _bridge.SendErrorAsync(id, "INTERNAL_ERROR", "操作已取消", token, "rshell.connect");            }            catch (Exception ex)            {                await _bridge.SendErrorAsync(id, "INTERNAL_ERROR", ex.Message, token, "rshell.connect");            }        }        private RShellConnectResultPayload DoConnect(string host, int port, int timeoutMs, int maxRetries, CancellationToken token)        {            var session = new RShellSession            {                Id = Guid.NewGuid().ToString("N"),                Host = host,                Port = port,                Status = "connecting",                TimeoutMs = timeoutMs,                MaxRetries = maxRetries,            };            try            {                var udp = new UdpClient();                udp.Connect(host, port);                session.Client = udp;                var hi = Encoding.UTF8.GetBytes("hi");                var welcome = false;                for (var attempt = 0; attempt <= maxRetries && !welcome; attempt++)                {                    token.ThrowIfCancellationRequested();                    lock (session.UdpLock)                    {                        udp.Send(hi, hi.Length);                    }                    if (TryReceiveWelcome(udp, timeoutMs, out var full) &&                        full.IndexOf("welcome", StringComparison.OrdinalIgnoreCase) >= 0)                    {                        welcome = true;                        break;                    }                }                if (!welcome)                {                    DisposeSession(session);                    return new RShellConnectResultPayload                    {                        ok = false,                        status = "error",                        error = "握手超时，未收到 welcome 响应",                        host = host,                        port = port,                    };                }                session.Status = "connected";                session.LastHeartbeatMs = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds();                Sessions[session.Id] = session;                session.HeartbeatTimer = new Timer(                    HeartbeatCallback,                    session,                    5000,                    5000);                return new RShellConnectResultPayload                {                    ok = true,                    connectionId = session.Id,                    status = "connected",                    host = host,                    port = port,                };            }            catch (Exception ex)            {                DisposeSession(session);                return new RShellConnectResultPayload                {                    ok = false,                    status = "error",                    error = ex.Message,                    host = host,                    port = port,                };            }        }        private static void HeartbeatCallback(object state)        {            var session = state as RShellSession;            if (session?.Client == null || session.Status != "connected")                return;            try            {                var hi = Encoding.UTF8.GetBytes("hi");                lock (session.UdpLock)                {                    session.Client.Send(hi, hi.Length);                }                if (!TryReceiveWelcome(session.Client, 3000, out var full) ||                    full.IndexOf("welcome", StringComparison.OrdinalIgnoreCase) < 0)                {                    session.MissCount++;                    if (session.MissCount >= 3)                    {                        session.Status = "error";                        session.Error = "心跳超时，连续 3 次无响应";                        session.HeartbeatTimer?.Dispose();                        session.HeartbeatTimer = null;                    }                }                else                {                    session.MissCount = 0;                    session.LastHeartbeatMs = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds();                }            }            catch            {                session.MissCount++;                if (session.MissCount >= 3)                {                    session.Status = "error";                    session.Error = "心跳异常";                    session.HeartbeatTimer?.Dispose();                    session.HeartbeatTimer = null;                }            }        }        private static bool TryReceiveWelcome(UdpClient udp, int overallTimeoutMs, out string assembled)        {            return TryReceiveAssembled(udp, overallTimeoutMs, out assembled);        }        private static bool TryReceiveAssembled(UdpClient udp, int overallTimeoutMs, out string assembled)        {            assembled = null;            var asm = new RShellFragmentAssembler();            var deadline = DateTime.UtcNow.AddMilliseconds(overallTimeoutMs);            var remote = new IPEndPoint(IPAddress.Any, 0);            while (DateTime.UtcNow < deadline)            {                var wait = (int)Math.Min(1000, (deadline - DateTime.UtcNow).TotalMilliseconds);                if (wait < 1)                    wait = 1;                try                {                    udp.Client.ReceiveTimeout = wait;                }                catch                {                    // ignored                }                byte[] data;                try                {                    data = udp.Receive(ref remote);                }                catch (SocketException)                {                    continue;                }                var text = Encoding.UTF8.GetString(data);                if (asm.TryAdd(text, out var full))                {                    assembled = full;                    return true;                }            }            return false;        }        private async Task HandleDisconnectAsync(string id, string json, CancellationToken token)        {            Logger.Log("RShell", $"断开连接: id={id}");            var msg = JsonUtility.FromJson<RShellConnectionIdMessage>(json);            var cid = msg?.payload?.connectionId ?? "";            if (string.IsNullOrEmpty(cid) || !Sessions.TryRemove(cid, out var s))            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", $"connectionId \"{cid}\" 不存在", token, "rshell.disconnect");                return;            }            Logger.Log("RShell", $"断开连接: connectionId={cid} id={id}");            await Task.Run(() => DisposeSession(s), token).ConfigureAwait(true);            Logger.Log("RShell", $"连接已断开: connectionId={cid}");            await _bridge.SendResultAsync(                id,                "rshell.disconnect",                new GenericOkPayload { ok = true, state = "disconnected" },                token);        }        private async Task HandleStatusAsync(string id, string json, CancellationToken token)        {            Logger.Log("RShell", $"查询状态 id={id}");            var msg = JsonUtility.FromJson<RShellStatusMessage>(json);            var cid = msg?.payload?.connectionId ?? "";            if (string.IsNullOrEmpty(cid))            {                var entries = Sessions.Values.Select(s => new RShellStatusEntry                {                    connectionId = s.Id,                    status = s.Status,                    host = s.Host,                    port = s.Port,                    lastHeartbeatAt = s.LastHeartbeatMs,                    error = s.Error,                }).ToArray();                await _bridge.SendResultAsync(id, "rshell.status", new RShellStatusResultPayload                {                    ok = true,                    status = "ok",                    connections = entries,                }, token);                return;            }            if (!Sessions.TryGetValue(cid, out var session))            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", $"connectionId \"{cid}\" 不存在", token, "rshell.status");                return;            }            await _bridge.SendResultAsync(id, "rshell.status", new RShellStatusResultPayload            {                ok = true,                connectionId = session.Id,                status = session.Status,                host = session.Host,                port = session.Port,                error = session.Error,                lastHeartbeatAt = session.LastHeartbeatMs,            }, token);        }        private Task HandleExecuteAsync(string id, string json, CancellationToken token)        {            var msg = JsonUtility.FromJson<RShellExecuteMessage>(json);            var p = msg?.payload ?? new RShellExecutePayload();            return ForwardExpression(id, p.connectionId, (p.expression ?? "").Trim(), "rshell.execute", token);        }        private Task HandleSceneListAsync(string id, string json, CancellationToken token)        {            var msg = JsonUtility.FromJson<RShellConnectionIdMessage>(json);            var cid = msg?.payload?.connectionId ?? "";            return ForwardExpression(id, cid, "Scene.List()", "rshell.scene_list", token);        }        private async Task HandleSceneInfoAsync(string id, string json, CancellationToken token)        {            Logger.Log("RShell", $"获取场景信息: id={id}");            var msg = JsonUtility.FromJson<RShellSceneInfoMessage>(json);            var p = msg?.payload ?? new RShellSceneInfoPayload();            var path = p.path ?? "";            var expr = $"Scene.Info({EscapeCsString(path)})";            await ForwardExpression(id, p.connectionId, expr, "rshell.scene_info", token);        }        private Task HandleGetValueAsync(string id, string json, CancellationToken token)        {            var msg = JsonUtility.FromJson<RShellGetValueMessage>(json);            var p = msg?.payload ?? new RShellGetValuePayload();            return ForwardExpression(id, p.connectionId, (p.expression ?? "").Trim(), "rshell.get_value", token);        }        private async Task HandleSetValueAsync(string id, string json, CancellationToken token)        {            Logger.Log("RShell", $"设置值 id={id}");            var msg = JsonUtility.FromJson<RShellSetValueMessage>(json);            var p = msg?.payload ?? new RShellSetValuePayload();            var e = (p.expression ?? "").Trim();            var v = p.value ?? "";            if (string.IsNullOrEmpty(e))            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", "expression 不能为空", token, "rshell.set_value");                return;            }            var expr = $"{e}={v}";            await ForwardExpression(id, p.connectionId, expr, "rshell.set_value", token);        }        private async Task HandleCallMethodAsync(string id, string json, CancellationToken token)        {            Logger.Log("RShell", $"调用方法: id={id}");            var msg = JsonUtility.FromJson<RShellCallMethodMessage>(json);            var p = msg?.payload ?? new RShellCallMethodPayload();            var e = (p.expression ?? "").Trim();            if (string.IsNullOrEmpty(e))            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", "expression 不能为空", token, "rshell.call_method");                return;            }            var args = p.args ?? "";            var expr = string.IsNullOrEmpty(args) ? $"{e}()" : $"{e}({args})";            await ForwardExpression(id, p.connectionId, expr, "rshell.call_method", token);        }        private async Task ForwardExpression(string id, string connectionId, string expression, string commandName, CancellationToken token)        {            if (string.IsNullOrWhiteSpace(expression))            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", "expression 不能为空", token, commandName);                return;            }            if (expression.Length > 10000)            {                await _bridge.SendErrorAsync(id, "INVALID_PAYLOAD", "expression 过长", token, commandName);                return;            }            if (!Sessions.TryGetValue(connectionId ?? "", out var session) || session.Status != "connected")            {                await _bridge.SendErrorAsync(                    id,                    "INVALID_PAYLOAD",                    $"连接 \"{connectionId}\" 不存在或未 connected",                    token,                    commandName);                return;            }            try            {                var sw = System.Diagnostics.Stopwatch.StartNew();                var payload = await Task.Run(() => DoExecute(session, expression, session.TimeoutMs, session.MaxRetries), token).ConfigureAwait(true);                sw.Stop();                payload.roundTripMs = sw.ElapsedMilliseconds;                await _bridge.SendResultAsync(id, commandName, payload, token);            }            catch (OperationCanceledException)            {                await _bridge.SendErrorAsync(id, "INTERNAL_ERROR", "操作已取消", token, commandName);            }        }        private static RShellExecuteResultPayload DoExecute(RShellSession session, string expression, int timeoutMs, int maxRetries)        {            try            {                var bytes = Encoding.UTF8.GetBytes(expression);                string assembled = null;                for (var attempt = 0; attempt <= maxRetries; attempt++)                {                    lock (session.UdpLock)                    {                        session.Client.Send(bytes, bytes.Length);                    }                    if (TryReceiveAssembled(session.Client, timeoutMs, out assembled))                    {                        session.LastHeartbeatMs = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds();                        session.MissCount = 0;                        return new RShellExecuteResultPayload                        {                            ok = true,                            status = "completed",                            result = assembled,                        };                    }                }                return new RShellExecuteResultPayload                {                    ok = false,                    status = "timeout",                    error = "执行超时，未收到响应",                };            }            catch (Exception ex)            {                return new RShellExecuteResultPayload                {                    ok = false,                    status = "error",                    error = ex.Message,                };            }        }    }}